package com.example.inventory.service;
import com.example.inventory.mapper.*; import com.example.inventory.model.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.text.SimpleDateFormat; import java.util.*;
@Service
public class InventoryService { private final ShopMapper shopMapper; private final BuyInMapper buyInMapper; private final SellOutMapper sellOutMapper; private final StorageMapper storageMapper; public InventoryService(ShopMapper s, BuyInMapper b, SellOutMapper o, StorageMapper st){this.shopMapper=s;this.buyInMapper=b;this.sellOutMapper=o;this.storageMapper=st;} public List<Shop> shops(){return shopMapper.findAll();} public Shop shop(String c){return shopMapper.findByCode(c);} public void saveShop(Shop s){if(shopMapper.findByCode(s.getShopCode())==null){shopMapper.insert(s);}else{shopMapper.update(s);}} public void deleteShop(String code){if(shopMapper.countStorage(code)>0){throw new IllegalArgumentException("该商品已有库存业务记录，不能删除");} shopMapper.delete(code);} public List<BuyIn> buyIns(){return buyInMapper.findAll();} public List<SellOut> sellOuts(){return sellOutMapper.findAll();} public List<Storage> storages(){return storageMapper.findAll();} public String nextBuyInCode(){return nextCode(buyInMapper.maxCodeLike(today()), today());} public String nextSellOutCode(){return nextCode(sellOutMapper.maxCodeLike(today()), today());} private String today(){return new SimpleDateFormat("yyyyMMdd").format(new Date());} private String nextCode(String max, String prefix){int n=max==null?1:Integer.parseInt(max.substring(8))+1; return prefix+String.format("%03d", n);} @Transactional public void addBuyIn(BuyIn b){positive(b.getNum()); b.setBuyInCode(nextBuyInCode()); b.setBuyDate(new Date()); buyInMapper.insert(b); Storage st=storageMapper.findByShopCode(b.getShopCode()); if(st==null){Storage ns=new Storage(); ns.setShopCode(b.getShopCode()); ns.setNum(b.getNum()); storageMapper.insert(ns);}else{storageMapper.increase(b.getShopCode(), b.getNum());}} @Transactional public void addSellOut(SellOut s){positive(s.getNum()); Storage st=storageMapper.findByShopCode(s.getShopCode()); if(st==null){throw new IllegalArgumentException("商品在库存表中不存在，不能保存");} if(st.getNum()<s.getNum()){throw new IllegalArgumentException("库存数量不足，不能保存");} s.setSellOutCode(nextSellOutCode()); s.setSellDate(new Date()); sellOutMapper.insert(s); storageMapper.decrease(s.getShopCode(), s.getNum());} private void positive(Integer n){if(n==null||n<=0){throw new IllegalArgumentException("数量必须大于0");}} }
